class Solution:
    def findAllPeople(self, n: int, meetings: List[List[int]], firstPerson: int) -> List[int]:
        meetings.sort(key=lambda x: x[2])
        parent = list(range(n))
        parent[firstPerson] = 0

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            root_x, root_y = find(x), find(y)
            if root_x < root_y:
                parent[root_y] = root_x
            else:
                parent[root_x] = root_y

        i = 0
        while i < len(meetings):
            group = []
            timestamp = meetings[i][2]
            while i < len(meetings) and meetings[i][2] == timestamp:
                x, y, _ = meetings[i]
                group.append((x, y))
                i += 1
            for x, y in group:
                union(x, y)
            for x, y in group:
                if find(x) != find(0):
                    parent[x] = x
                if find(y) != find(0):
                    parent[y] = y

        return [i for i in range(n) if find(i) == find(0)]

